[CmdletBinding()]param([string]$ProbeA='evidence/M00/F2S-DEV-M00-001/F2S-WU-M00-001-02/clean-vm-a/probe.json',[string]$ProbeB='evidence/M00/F2S-DEV-M00-001/F2S-WU-M00-001-02/clean-vm-b/probe.json',[string]$Output='evidence/M01/F2S-DEV-M01-002/F2S-WU-M01-002-03/clean-vm-diff.json')
$ErrorActionPreference='Stop';$state='NOT_RUN';$issues=@();if((Test-Path $ProbeA) -and (Test-Path $ProbeB)){$a=Get-Content $ProbeA -Raw|ConvertFrom-Json;$b=Get-Content $ProbeB -Raw|ConvertFrom-Json;foreach($id in @($a.tools.id|Sort-Object -Unique)){$ta=@($a.tools|? id -eq $id)[0];$tb=@($b.tools|? id -eq $id)[0];if($ta.version -cne $tb.version -or $ta.sha256 -cne $tb.sha256){$issues+=@{id=$id;code='RUNNER_DRIFT';aVersion=$ta.version;bVersion=$tb.version}};$state=if($issues.Count){'FAIL'}else{'PASS'}}else{$issues+=@{code='CLEAN_VM_EVIDENCE_MISSING';paths=@($ProbeA,$ProbeB)}};$result=[ordered]@{schemaVersion='1.0.0';status=$state;capabilityState=if($state-eq'PASS'){'VERIFIED'}else{'UNVERIFIED'};issues=$issues};$parent=Split-Path -Parent $Output;if(-not(Test-Path $parent)){New-Item -ItemType Directory $parent|Out-Null};[IO.File]::WriteAllText((Join-Path (Get-Location) $Output),(($result|ConvertTo-Json -Depth 8)+[Environment]::NewLine),[Text.UTF8Encoding]::new($false));$result
